class AuthenticationManager: ObservableObject {
    @Published var isAuthenticated: Bool {
        didSet {
            UserDefaults.standard.set(isAuthenticated, forKey: "isAuthenticated")
        }
    }

    private let context = LAContext()
    private var error: NSError?

    init() {
        self.isAuthenticated = UserDefaults.standard.bool(forKey: "isAuthenticated")
    }

    func authenticateWithBiometrics(reason: String, completion: @escaping (Bool, LAError?) -> Void) {
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error as? LAError)
            return
        }

        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, authenticationError in
            DispatchQueue.main.async {
                self.isAuthenticated = success
                completion(success, authenticationError as? LAError)
            }
        }
    }

    func authenticateWithPasscode(reason: String, completion: @escaping (Bool, LAError?) -> Void) {
        guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
            completion(false, error as? LAError)
            return
        }

        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, authenticationError in
            DispatchQueue.main.async {
                self.isAuthenticated = success
                completion(success, authenticationError as? LAError)
            }
        }
    }

    func resetAuthentication() {
        isAuthenticated = false
    }

    func biometricType() -> LABiometryType {
        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) {
            return context.biometryType
        }
        return .none
    }
}

