struct LoginView: View {
    @EnvironmentObject var authManager: AuthenticationManager
    @State private var showingBiometricAlert = false
    @State private var biometricAuthFailed = false
    @State private var biometricAuthErrorMessage: String?

    var body: some View {
        VStack {
            Text("Welcome to the App!")
                .font(.largeTitle)
                .padding()

            Spacer()

            if authManager.biometricType() != .none {
                Button(action: {
                    authenticateBiometrics()
                }) {
                    HStack {
                        Image(systemName: authManager.biometricType() == .faceID ? "faceid" : "touchid")
                            .font(.title)
                        Text("Authenticate with \(authManager.biometricType() == .faceID ? "Face ID" : "Touch ID")")
                    }
                    .padding()
                    .background(Color.blue)
                    .foregroundColor(.white)
                    .cornerRadius(10)
                }
                .padding()
            }

            if biometricAuthFailed {
                Text(biometricAuthErrorMessage ?? "Biometric authentication failed.")
                    .foregroundColor(.red)
                    .padding(.horizontal)

                Button("Retry Biometrics") {
                    authenticateBiometrics()
                }
                .padding()
                .background(Color.orange)
                .foregroundColor(.white)
                .cornerRadius(10)

                Text("OR")
                    .padding(.vertical, 5)

                Button("Enter Password") {
                    // In a real app, this would navigate to a password login view or show a sheet.
                    // For this example, we'll simulate a successful password login.
                    authenticateWithPasswordFallback()
                }
                .padding()
                .background(Color.green)
                .foregroundColor(.white)
                .cornerRadius(10)
            } else if authManager.biometricType() == .none {
                Text("Biometric authentication not available or configured.")
                    .foregroundColor(.gray)
                    .padding()

                Button("Login with Password") {
                    // Simulate password login
                    authenticateWithPasswordFallback()
                }
                .padding()
                .background(Color.green)
                .foregroundColor(.white)
                .cornerRadius(10)
            }

            Spacer()
        }
        .onAppear {
            if authManager.isAuthenticated {
                // If already authenticated (e.g., from previous session),
                // the ContentView will directly show HomeView.
                // No need to trigger biometrics here.
            } else {
                // Try biometric authentication automatically if available on first load
                if authManager.biometricType() != .none {
                    authenticateBiometrics()
                }
            }
        }
        .alert(isPresented: $showingBiometricAlert) {
            Alert(
                title: Text("Biometric Authentication Error"),
                message: Text(biometricAuthErrorMessage ?? "An unknown error occurred during biometric authentication."),
                primaryButton: .default(Text("Try Again")) {
                    authenticateBiometrics()
                },
                secondaryButton: .cancel(Text("Enter Password")) {
                    authenticateWithPasswordFallback()
                }
            )
        }
    }

    private func authenticateBiometrics() {
        biometricAuthFailed = false
        biometricAuthErrorMessage = nil

        authManager.authenticateWithBiometrics(reason: "Authenticate to access your account.") { success, error in
            if success {
                print("Biometric authentication successful!")
            } else {
                print("Biometric authentication failed: \(error?.localizedDescription ?? "Unknown error")")
                biometricAuthFailed = true
                biometricAuthErrorMessage = errorMessage(for: error)
            }
        }
    }

    private func authenticateWithPasswordFallback() {
        // In a real app, you would prompt for a password here.
        // For demonstration, we'll simulate success.
        authManager.authenticateWithPasscode(reason: "Enter your device passcode to access the app.") { success, error in
            if success {
                print("Passcode authentication successful!")
            } else {
                print("Passcode authentication failed: \(error?.localizedDescription ?? "Unknown error")")
                biometricAuthFailed = true // Re-using this flag to indicate general auth failure
                biometricAuthErrorMessage = "Passcode authentication failed. Please try again or restart."
            }
        }
    }

    private func errorMessage(for error: LAError?) -> String {
        guard let error = error else { return "Authentication failed." }

        switch error.code {
        case .userCancel:
            return "Authentication cancelled by user."
        case .userFallback:
            return "User chose to enter password."
        case .systemCancel:
            return "Authentication cancelled by system."
        case .passcodeNotSet:
            return "Device Passcode not set. Please set a passcode to use biometrics."
        case .biometryNotAvailable:
            return "Biometric authentication not available on this device."
        case .biometryNotEnrolled:
            return "No biometrics enrolled. Please enroll Face ID or Touch ID in Settings."
        case .biometryLockout:
            return "Biometrics locked out. Too many failed attempts. Try again later or use passcode."
        default:
            return "Authentication failed: \(error.localizedDescription)"
        }
    }
}

